#include <stdio.h>
#include <time.h>
#include <string.h>

void log_error(FILE *logfile, const char *error_msg, const char *function_name, int line_number) {
    if (logfile == NULL) {
        return;
    }
    
    time_t now;
    time(&now);
    char *timestamp = ctime(&now);
    timestamp[strlen(timestamp) - 1] = '\0';
    
    fprintf(logfile, "[ERROR] %s | Function: %s | Line: %d | Message: %s\n", 
            timestamp, function_name, line_number, error_msg);
    fflush(logfile);
}

